"use client"

import { type FormEvent, useState } from "react"
import { useRouter } from "next/navigation"
import { signIn } from "next-auth/react"

import { useAppToast } from "@/app/components/AppToastProvider"
import { ACCOUNT_PLAN_OPTIONS } from "@/lib/platform"

const roleCards = [
  {
    value: "CLIENT",
    title: "Sou tutor",
    description: "Quero acompanhar meu cao, acessar conteudos, organizar rotina e evoluir com mais constancia.",
  },
  {
    value: "TRAINER",
    title: "Sou profissional de treino",
    description: "Quero atender alunos, abrir meu canal, publicar conteudos e organizar meus atendimentos com mais clareza.",
  },
  {
    value: "VET",
    title: "Sou profissional de saude",
    description: "Quero orientar responsaveis, compartilhar guias e participar da jornada de cuidado com mais contexto.",
  },
] as const

export default function RegisterPage() {
  const router = useRouter()
  const { pushToast } = useAppToast()

  const [role, setRole] = useState<(typeof roleCards)[number]["value"]>("CLIENT")
  const [plan, setPlan] = useState<(typeof ACCOUNT_PLAN_OPTIONS)[number]["code"]>("FREE")
  const [name, setName] = useState("")
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [phone, setPhone] = useState("")
  const [city, setCity] = useState("")
  const [state, setState] = useState("")
  const [message, setMessage] = useState("")
  const [loading, setLoading] = useState(false)

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    setLoading(true)
    setMessage("")

    const normalizedEmail = email.trim().toLowerCase()

    try {
      const res = await fetch("/api/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          name,
          email: normalizedEmail,
          password,
          phone,
          role,
          plan,
          city,
          state,
        }),
      })

      const data = await res.json().catch(() => null)

      if (res.ok && data?.success) {
        const note =
          plan === "FREE"
            ? "Conta criada com sucesso. Agora vamos confirmar seu email para liberar a experiencia completa."
            : "Conta criada com sucesso. Vamos confirmar seu email e depois seguir para a assinatura do plano escolhido."

        setMessage(note)
        pushToast({ title: "Conta criada", description: note, variant: "success" })

        const login = await signIn("credentials", { email: normalizedEmail, password, redirect: false })
        if (login?.error) {
          const fallback = "Sua conta foi criada, mas o login automatico nao aconteceu. Voce pode entrar manualmente sem problema."
          setMessage(fallback)
          pushToast({ title: "Login manual necessario", description: fallback, variant: "info" })
          return
        }

        router.push(plan === "FREE" ? "/verify" : `/verify?next=billing&plan=${plan}`)
        return
      }

      const note = data?.message || "Nao foi possivel criar sua conta agora. Tente novamente em alguns instantes."
      setMessage(note)
      pushToast({ title: "Cadastro nao concluido", description: note, variant: "error" })
    } catch (error) {
      console.error(error)
      const note = "Ops, algo deu errado ao criar sua conta. Tente novamente em alguns instantes."
      setMessage(note)
      pushToast({ title: "Falha no cadastro", description: note, variant: "error" })
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-[100svh] bg-[radial-gradient(circle_at_top,rgba(34,211,238,0.18),transparent_28%),linear-gradient(145deg,#020617,#0f172a_50%,#020617)] text-white">
      <div className="mx-auto flex min-h-[100svh] max-w-6xl flex-col gap-10 px-4 py-12 sm:px-6 lg:flex-row lg:items-center">
        <div className="flex-1 space-y-6 fade-in-up">
          <span className="inline-flex items-center gap-2 rounded-full border border-cyan-300/20 bg-cyan-500/10 px-3 py-1 text-xs uppercase tracking-[0.28em] text-cyan-100">
            Onboarding acolhedor
          </span>
          <div className="space-y-4">
            <h1 className="max-w-2xl text-4xl font-bold leading-tight md:text-5xl">Comece com o papel certo e a plataforma te acompanha daqui pra frente.</h1>
            <p className="max-w-2xl text-lg leading-8 text-slate-300">
              O cadastro foi pensado para ser direto: voce escolhe seu momento, conta um pouco sobre voce e depois seguimos juntos para verificar a conta e liberar os recursos certos.
            </p>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            {roleCards.map((item) => {
              const active = role === item.value
              return (
                <button
                  key={item.value}
                  type="button"
                  onClick={() => setRole(item.value)}
                  className={`interactive-card rounded-[24px] border p-5 text-left transition ${
                    active
                      ? "border-cyan-300/50 bg-cyan-500/15 shadow-lg shadow-cyan-500/15"
                      : "border-white/10 bg-white/5 hover:bg-white/10"
                  }`}
                >
                  <p className="text-lg font-semibold">{item.title}</p>
                  <p className="mt-2 text-sm leading-7 text-slate-300">{item.description}</p>
                </button>
              )
            })}
          </div>
        </div>

        <div className="flex-1 fade-in-up">
          <div className="surface-card mx-auto w-full max-w-xl rounded-[32px] p-8 shadow-2xl backdrop-blur-xl">
            <div className="mb-6">
              <p className="text-sm uppercase tracking-[0.2em] text-cyan-200/80">Cadastro</p>
              <h2 className="text-2xl font-semibold">Conte um pouco sobre voce</h2>
              <p className="mt-2 text-sm leading-7 text-slate-300">
                Assim conseguimos preparar uma experiencia mais coerente com sua rotina. Depois do cadastro, vamos pedir a confirmacao do email para proteger a conta.
              </p>
            </div>

            <form className="flex flex-col gap-4" onSubmit={handleSubmit}>
              <div className="flex flex-col gap-2">
                <label htmlFor="role" className="text-sm text-slate-200/80">Tipo de conta</label>
                <select
                  id="role"
                  value={role}
                  onChange={(event) => setRole(event.target.value as (typeof roleCards)[number]["value"])}
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                >
                  <option value="CLIENT" className="text-black">Tutor</option>
                  <option value="TRAINER" className="text-black">Profissional de treino</option>
                  <option value="VET" className="text-black">Profissional de saude</option>
                </select>
              </div>

              <div className="flex flex-col gap-2">
                <label className="text-sm text-slate-200/80">Plano inicial</label>
                <div className="grid gap-3">
                  {ACCOUNT_PLAN_OPTIONS.map((item) => {
                    const active = plan === item.code
                    return (
                      <button
                        key={item.code}
                        type="button"
                        onClick={() => setPlan(item.code)}
                        className={`interactive-card rounded-2xl border p-4 text-left transition ${
                          active
                            ? "border-cyan-300/50 bg-cyan-500/15 shadow-lg shadow-cyan-500/10"
                            : "border-white/10 bg-white/5 hover:bg-white/10"
                        }`}
                      >
                        <div className="flex items-center justify-between gap-4">
                          <div>
                            <p className="text-base font-semibold">{item.name}</p>
                            <p className="mt-1 text-sm leading-7 text-slate-300">{item.description}</p>
                          </div>
                          <span className="text-sm font-semibold text-cyan-100">{item.priceLabel}</span>
                        </div>
                      </button>
                    )
                  })}
                </div>
              </div>

              <div className="flex flex-col gap-2">
                <label htmlFor="name" className="text-sm text-slate-200/80">Nome</label>
                <input
                  id="name"
                  type="text"
                  placeholder="Como voce gostaria de ser chamado?"
                  value={name}
                  onChange={(event) => setName(event.target.value)}
                  required
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label htmlFor="email" className="text-sm text-slate-200/80">Email</label>
                <input
                  id="email"
                  type="email"
                  autoComplete="email"
                  placeholder="voce@exemplo.com"
                  value={email}
                  onChange={(event) => setEmail(event.target.value)}
                  required
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label htmlFor="password" className="text-sm text-slate-200/80">Senha</label>
                <input
                  id="password"
                  type="password"
                  autoComplete="new-password"
                  placeholder="Crie uma senha segura"
                  value={password}
                  onChange={(event) => setPassword(event.target.value)}
                  required
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="flex flex-col gap-2">
                <label htmlFor="phone" className="text-sm text-slate-200/80">Telefone</label>
                <input
                  id="phone"
                  type="tel"
                  autoComplete="tel"
                  placeholder="+55 67 9xxxx-xxxx"
                  value={phone}
                  onChange={(event) => setPhone(event.target.value)}
                  className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                />
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <div className="flex flex-col gap-2">
                  <label htmlFor="city" className="text-sm text-slate-200/80">Cidade</label>
                  <input
                    id="city"
                    type="text"
                    placeholder="Onde voce esta?"
                    value={city}
                    onChange={(event) => setCity(event.target.value)}
                    className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                  />
                </div>

                <div className="flex flex-col gap-2">
                  <label htmlFor="state" className="text-sm text-slate-200/80">Estado</label>
                  <input
                    id="state"
                    type="text"
                    placeholder="UF"
                    value={state}
                    onChange={(event) => setState(event.target.value.toUpperCase())}
                    maxLength={2}
                    className="w-full rounded-2xl border border-white/10 bg-white/10 px-4 py-3 text-white placeholder:text-slate-400 focus:border-cyan-300/70 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
                  />
                </div>
              </div>

              <div className="rounded-2xl border border-emerald-300/15 bg-emerald-500/10 p-4 text-sm leading-7 text-emerald-50">
                {plan === "FREE" ? (
                  <>
                    Voce entra pelo <strong>plano Free</strong> com calma para conhecer a plataforma. Depois do cadastro, recomendamos confirmar o email e completar o perfil para aproveitar melhor os recursos.
                  </>
                ) : (
                  <>
                    Seu cadastro ja reserva o plano <strong>{plan}</strong>. Depois da verificacao de email, seguimos para a assinatura para liberar os recursos completos.
                  </>
                )}
              </div>

              <button
                type="submit"
                disabled={loading}
                className="interactive-button mt-2 flex items-center justify-center gap-2 rounded-2xl bg-[linear-gradient(135deg,#06b6d4,#10b981)] px-4 py-3 font-semibold text-white shadow-lg shadow-cyan-500/20 disabled:cursor-not-allowed disabled:opacity-60"
              >
                {loading ? "Criando sua conta..." : "Criar minha conta"}
              </button>
            </form>

            {message ? <p className="mt-4 text-sm leading-7 text-cyan-100">{message}</p> : null}
          </div>
        </div>
      </div>
    </div>
  )
}
